  1	import React, { FC, useCallback, useState } from 'react';
  2	import produce from 'immer';
  3	
  4	import { TemplateModel, V1Template } from '@kubevirt-ui/kubevirt-api/console';
  5	import ConfirmActionMessage from '@kubevirt-utils/components/ConfirmActionMessage/ConfirmActionMessage';
  6	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
  7	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
  8	import KebabToggle from '@kubevirt-utils/components/toggles/KebabToggle';
  9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 10	import { getTemplateVirtualMachineObject } from '@kubevirt-utils/resources/template';
 11	import { NetworkPresentation } from '@kubevirt-utils/resources/vm/utils/network/constants';
 12	import { getContentScrollableElement } from '@kubevirt-utils/utils/utils';
 13	import { k8sUpdate } from '@openshift-console/dynamic-plugin-sdk';
 14	import { ButtonVariant, Dropdown, DropdownItem, DropdownList } from '@patternfly/react-core';
 15	
 16	import useEditTemplateAccessReview from '../../../../hooks/useIsTemplateEditable';
 17	import TemplatesEditNetworkInterfaceModal from '../modal/TemplatesEditNetworkInterfaceModal';
 18	
 19	type NetworkInterfaceActionsProps = {
 20	  nicName: string;
 21	  nicPresentation: NetworkPresentation;
 22	  template: V1Template;
 23	};
 24	
 25	const NetworkInterfaceActions: FC<NetworkInterfaceActionsProps> = ({
 26	  nicName,
 27	  nicPresentation,
 28	  template,
 29	}) => {
 30	  const { t } = useKubevirtTranslation();
 31	  const { createModal } = useModal();
 32	  const { isTemplateEditable } = useEditTemplateAccessReview(template);
 33	
 34	  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
 35	  const label = t('Delete NIC?');
 36	  const editBtnText = t('Edit');
 37	  const submitBtnText = t('Delete');
 38	
 39	  const onEditModalOpen = () => {
 40	    createModal(({ isOpen, onClose }) => (
 41	      <TemplatesEditNetworkInterfaceModal
 42	        isOpen={isOpen}
 43	        nicPresentation={nicPresentation}
 44	        onClose={onClose}
 45	        template={template}
 46	      />
 47	    ));
 48	  };
 49	
 50	  const onDelete = useCallback(() => {
 51	    const updatedTemplate = produce(template, (draftTemplate) => {
 52	      const vm = getTemplateVirtualMachineObject(draftTemplate);
 53	      vm.spec.template.spec.networks = vm.spec.template.spec.networks.filter(
 54	        ({ name }) => name !== nicName,
 55	      );
 56	      vm.spec.template.spec.domain.devices.interfaces =
 57	        vm.spec.template.spec.domain.devices.interfaces.filter(({ name }) => name !== nicName);
 58	    });
 59	
 60	    return k8sUpdate({
 61	      data: updatedTemplate,
 62	      model: TemplateModel,
 63	      name: updatedTemplate?.metadata?.name,
 64	      ns: updatedTemplate?.metadata?.namespace,
 65	    });
 66	  }, [nicName, template]);
 67	
 68	  const onDeleteModalToggle = () => {
 69	    createModal(({ isOpen, onClose }) => (
 70	      <TabModal<V1Template>
 71	        headerText={label}
 72	        isOpen={isOpen}
 73	        obj={template}
 74	        onClose={onClose}
 75	        onSubmit={onDelete}
 76	        submitBtnText={submitBtnText}
 77	        submitBtnVariant={ButtonVariant.danger}
 78	      >
 79	        <ConfirmActionMessage
 80	          obj={{ metadata: { name: nicName, namespace: template?.metadata?.namespace } }}
 81	        />
 82	      </TabModal>
 83	    ));
 84	  };
 85	
 86	  const onToggle = () => setIsDropdownOpen((prevIsOpen) => !prevIsOpen);
 87	
 88	  return (
 89	    <Dropdown
 90	      toggle={KebabToggle({
 91	        id: 'toggle-id-6',
 92	        isDisabled: !isTemplateEditable,
 93	        isExpanded: isDropdownOpen,
 94	        onClick: onToggle,
 95	      })}
 96	      isOpen={isDropdownOpen}
 97	      onOpenChange={(open: boolean) => setIsDropdownOpen(open)}
 98	      onSelect={() => setIsDropdownOpen(false)}
 99	      popperProps={{ appendTo: getContentScrollableElement, position: 'right' }}
100	    >
101	      <DropdownList>
102	        <DropdownItem key="network-interface-edit" onClick={onEditModalOpen}>
103	          {editBtnText}
104	        </DropdownItem>
105	        <DropdownItem key="network-interface-delete" onClick={onDeleteModalToggle}>
106	          {submitBtnText}
107	        </DropdownItem>
108	      </DropdownList>
109	    </Dropdown>
110	  );
111	};
112	
113	export default NetworkInterfaceActions;

